import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ContentType = 'Blog Post' | 'Social Media' | 'Email Campaign' | 'Ad Copy';
export type Tone = 'Professional' | 'Casual' | 'Witty' | 'Authoritative' | 'Inspirational';

export interface WorkflowConfig {
  topic: string;
  contentType: ContentType;
  tone: Tone;
  targetAudience: string;
  generateImages: boolean;
  webhookUrl?: string;
}

export interface WorkflowStep {
  id: string;
  label: string;
  status: 'idle' | 'running' | 'completed' | 'failed';
  result?: string;
}

export interface GenerationResult {
  id: string;
  timestamp: number;
  config: WorkflowConfig;
  text: string;
  imageUrl?: string;
  metrics: {
    readingTime: number;
    keywordDensity: number;
    sentiment: string;
  };
}

export enum AppStatus {
  IDLE = 'IDLE',
  EXECUTING = 'EXECUTING',
  VIEWING = 'VIEWING'
}

import { GoogleGenAI, Type } from "@google/genai";
import { WorkflowConfig, GenerationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function generateWorkflowContent(config: WorkflowConfig): Promise<GenerationResult> {
  // Use gemini-3-flash-preview for fast content generation
  const textResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a detailed ${config.contentType} about "${config.topic}". 
    Target Audience: ${config.targetAudience}. 
    Tone: ${config.tone}. 
    Include a title and structured content.`,
    config: {
      temperature: 0.8,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          body: { type: Type.STRING },
          metrics: {
            type: Type.OBJECT,
            properties: {
              readingTime: { type: Type.NUMBER },
              sentiment: { type: Type.STRING },
              keywordDensity: { type: Type.NUMBER }
            },
            required: ['readingTime', 'sentiment', 'keywordDensity']
          }
        },
        required: ['title', 'body', 'metrics']
      }
    }
  });

  const contentData = JSON.parse(textResponse.text || '{}');
  let imageUrl: string | undefined = undefined;

  if (config.generateImages) {
    try {
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `A high-quality editorial cover image for a blog post about ${config.topic}. Style: Modern, clean, professional.` }]
        },
        config: {
          imageConfig: {
            aspectRatio: "16:9"
          }
        }
      });

      for (const part of imgResponse.candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    } catch (e) {
      console.error("Image generation failed", e);
    }
  }

  return {
    id: crypto.randomUUID(),
    timestamp: Date.now(),
    config,
    text: `## ${contentData.title}\n\n${contentData.body}`,
    imageUrl,
    metrics: contentData.metrics
  };
}

