import { GoogleGenAI, Type } from "@google/genai";
import { WorkflowConfig, GenerationResult } from "../types";

export async function generateWorkflowContent(config: WorkflowConfig): Promise<GenerationResult> {
  // Always initialize GoogleGenAI with the API key from process.env.API_KEY
  // Create a new instance right before making the API call as per guidelines.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Use gemini-3-flash-preview for fast content generation
  const textResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a detailed ${config.contentType} about "${config.topic}". 
    Target Audience: ${config.targetAudience}. 
    Tone: ${config.tone}. 
    Include a title and structured content.`,
    config: {
      temperature: 0.8,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          body: { type: Type.STRING },
          metrics: {
            type: Type.OBJECT,
            properties: {
              readingTime: { type: Type.NUMBER },
              sentiment: { type: Type.STRING },
              keywordDensity: { type: Type.NUMBER }
            },
            required: ['readingTime', 'sentiment', 'keywordDensity']
          }
        },
        required: ['title', 'body', 'metrics']
      }
    }
  });

  // Extract generated text directly from the .text property
  const contentData = JSON.parse(textResponse.text || '{}');
  let imageUrl: string | undefined = undefined;

  if (config.generateImages) {
    try {
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `A high-quality editorial cover image for a blog post about ${config.topic}. Style: Modern, clean, professional.` }]
        },
        config: {
          imageConfig: {
            aspectRatio: "16:9"
          }
        }
      });

      // Iterate through parts to find the image part, as it may not be the first part.
      if (imgResponse.candidates?.[0]?.content?.parts) {
        for (const part of imgResponse.candidates[0].content.parts) {
          if (part.inlineData) {
            imageUrl = `data:image/png;base64,${part.inlineData.data}`;
            break;
          }
        }
      }
    } catch (e) {
      console.error("Image generation failed", e);
    }
  }

  return {
    id: crypto.randomUUID(),
    timestamp: Date.now(),
    config,
    text: `## ${contentData.title}\n\n${contentData.body}`,
    imageUrl,
    metrics: contentData.metrics
  };
}

