                     </div>
                   </div>
                </div>
              </div>
            </div>
          )}

          {status === AppStatus.EXECUTING && (
            <div className="max-w-2xl mx-auto py-12">
               <div className="text-center mb-10">
                 <div className="inline-block p-4 bg-blue-50 rounded-full mb-4">
