// The specific test webhook provided by the user
const N8N_WEBHOOK_URL = 'https://kandjtech.app.n8n.cloud/webhook-test/885b3900-d6f2-4caf-94f9-cd5f90427209';

// Redirect destination for the N8N dashboard on the user's cloud instance
const N8N_EXECUTION_VIEW_URL = 'https://kandjtech.app.n8n.cloud/home/workflows';

export async function triggerN8NWorkflow(config: WorkflowConfig): Promise<{ success: boolean; executionId?: string }> {
  try {
    const response = await fetch(N8N_WEBHOOK_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ...config,
        triggeredAt: new Date().toISOString(),
        source: 'FlowForge-Frontend-Orchestrator',
        metadata: {
          client: 'Web-UI',
          version: '2.4.0'
        }
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error(`N8N Webhook Error (${response.status}):`, errorText);
      throw new Error(`N8N Webhook failed: ${response.statusText}`);
    }

    // Attempt to parse response as JSON. N8N sometimes returns a simple string.
    let data;
    try {
      data = await response.json();
    } catch (e) {
      data = { status: 'success' };
    }

    return { 
      success: true, 
      executionId: data.executionId || data.id || 'N8N-HANDOFF-SUCCESS' 
    };
  } catch (error) {
    console.error("Critical Handoff Error:", error);
    // Even in test mode, we want to know if it failed.
    // We return success: false to prevent the UI from redirecting if the bridge didn't connect.
    return { success: false }; 
  }
}

/**
 * Returns the URL where the user can view the execution status
 * inside the N8N environment.
 */
export function getRedirectUrl() {
  return N8N_EXECUTION_VIEW_URL;
}

