export async function triggerN8NWorkflow(config: WorkflowConfig): Promise<{ success: boolean; error?: string }> {
  try {
    // 1. Construct the payload exactly as requested in the example
    // We wrap it in an array because many N8N workflows expect an array of items.
    const payload = [
      {
        "Platform": config.contentType || [],
        "Image Desired?": config.generateImages ? "Yes" : "No",
        "Topic": config.topic || "No Topic Provided",
        "Tone": config.tone || [],
        "Image Description": config.imageContext || "",
        "submittedAt": new Date().toISOString(),
        "formMode": "production"
      }
    ];

    // Log for debugging (Open Browser Console to see this)
    console.log("FlowForge >> Sending Payload to N8N:", JSON.stringify(payload, null, 2));

    const response = await fetch(N8N_WEBHOOK_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: JSON.stringify(payload),
    });

