import { WorkflowConfig } from "../types";

/**
 * N8N PRODUCTION ENDPOINTS
 * Blog Orchestrator (Webhook): https://kandjtech.app.n8n.cloud/webhook/472e9bac-9aa8-4c02-b037-494ff43262ec
 * Social Media Orchestrator (Form Endpoint): https://kandjtech.app.n8n.cloud/form/70a54f39-0994-4dce-8aa5-303a9c3dc6cf
 */
const N8N_BLOG_WEBHOOK_URL = 'https://kandjtech.app.n8n.cloud/webhook/472e9bac-9aa8-4c02-b037-494ff43262ec';
const N8N_SOCIAL_WEBHOOK_URL = 'https://kandjtech.app.n8n.cloud/form/70a54f39-0994-4dce-8aa5-303a9c3dc6cf';
const N8N_EXECUTION_VIEW_URL = 'https://kandjtech.app.n8n.cloud/home/workflows';

export async function triggerN8NWorkflow(config: WorkflowConfig): Promise<{ success: boolean; error?: string }> {
  try {
    // Determine the workflow context
    const isBlog = config.contentType.includes('Blog Post');
    const isSocial = config.contentType.some(t => 
      ['EXAIR - LinkedIn', 'EXAIR Corporation - Facebook', 'exair_corporation - Instagram', 'EXAIR - Twitter'].includes(t)
    );

    let url = '';
    let payload: any[] = [];

    if (isBlog) {
      // Use Blog Endpoint and Payload Mapping
      url = N8N_BLOG_WEBHOOK_URL;
      payload = [
        {
          "Content Topic": config.topic || "No Topic Provided",
          "Tone of Voice": config.tone || [],
          "Image Needed?": config.generateImages ? "Yes" : "No",
          "Image Context/Prompt": config.imageContext || "",
          "submittedAt": new Date().toISOString(),
          "formMode": "production"
        }
      ];
    } else if (isSocial) {
      // Use Social Media Endpoint and Payload Mapping
      url = N8N_SOCIAL_WEBHOOK_URL;
      payload = [
        {
          "Platform": config.contentType || [],
          "Topic": config.topic || "No Topic Provided",
          "Tone": config.tone || [],
          "Image Desired?": config.generateImages ? "Yes" : "No",
          "Image Description": config.imageContext || "",
          "submittedAt": new Date().toISOString(),
          "formMode": "production"
        }
      ];
    } else {
      // Fallback for other content types
      url = N8N_BLOG_WEBHOOK_URL; // Default fallback
      payload = [{
        ...config,
        submittedAt: new Date().toISOString(),
        formMode: "production"
      }];
    }

    // Log the transaction details for easy debugging in the browser console
    console.group(`FlowForge >> N8N Handoff (${isBlog ? 'BLOG' : isSocial ? 'SOCIAL' : 'GENERAL'} PRODUCTION)`);
    console.log("Target Endpoint:", url);
    console.log("Transmitting Payload:", payload);
    console.groupEnd();

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      // Capture detailed error info from N8N if available
      const errorData = await response.json().catch(() => ({ message: response.statusText }));
      const errorMessage = errorData.message || `HTTP ${response.status}`;

      console.error(`N8N Webhook Failed (${response.status}):`, errorData);
      return { success: false, error: errorMessage };
    }

    return { success: true };
  } catch (error: any) {
    console.error("Critical Handoff Error:", error);
    return { success: false, error: error.message || "Network Error" }; 
  }
}

